#!/usr/bin/env bun
// Generated by minsky compile. Do not edit directly.
// Source: .minsky/hooks/ask-grant-store.ts

// Shared, dependency-free store for approved-Ask action grants (mt#2823).
//
// Third instance of the ADR-028 file-based grant-store pattern: D5's
// `merge-grant-store.ts` (single guard, taskId scope), D8's
// `guard-grant-store.ts` (any guard/scope pair), and now ask-action grants —
// a responded `authorization.approve` Ask materialized into a narrow,
// TTL-bound, ONE-SHOT authorization for a specific tool call shape, consumed
// by `.minsky/hooks/ask-permission-bridge.ts` (PreToolUse) to emit the
// harness `permissionDecision: "allow"`.
//
// ## Security model (differs from D5/D8 in one load-bearing way)
//
// D5/D8 grants gate OVERRIDES of Minsky's own guards; this store gates an
// AUTO-ALLOW of the harness permission system — a stronger consequence. The
// store is therefore NOT the authority: the bridge hook re-verifies the
// referenced Ask server-side (state, kind, responder, response value) before
// honoring any grant, so a hand-written store entry fails verification. See
// the bridge hook's doc block for the full ladder.
//
// One-shot consumption: a grant is marked `consumedAt` BEFORE the allow is
// emitted; consumed grants never match again. TTL default is deliberately
// short (15 min) — a grant is minted for an action about to run, not a
// standing capability.
//
// Self-containment (per `.claude/hooks/SPEC.md`): imports ONLY `node:fs`,
// `node:os`, `node:path` — no `packages/domain` import, so the hook keeps
// working even when the main codebase has type errors.
//
// @see mt#2823 — this module's tracking task
// @see .minsky/hooks/guard-grant-store.ts — the D8 pattern this mirrors
// @see scripts/grant-ask-action.ts — the issuance surface

import * as fs from "fs";
import * as os from "os";
import * as path from "path";

// ---------------------------------------------------------------------------
// State-dir + store-path resolution (mirrors guard-grant-store.ts exactly)
// ---------------------------------------------------------------------------

const ASK_GRANT_STORE_FILENAME = "ask-grants.json";

/** Resolve the Minsky state dir: MINSKY_STATE_DIR, else XDG_STATE_HOME/minsky, else ~/.local/state/minsky. */
export function getStateDir(): string {
  const override = process.env["MINSKY_STATE_DIR"];
  if (override) return override;
  const xdgStateHome =
    process.env["XDG_STATE_HOME"] || path.join(process.env["HOME"] || os.homedir(), ".local/state");
  return path.join(xdgStateHome, "minsky");
}

/** Absolute path to the shared ask-grant store file. */
export function getAskGrantStorePath(): string {
  return path.join(getStateDir(), ASK_GRANT_STORE_FILENAME);
}

// ---------------------------------------------------------------------------
// Grant record shape
// ---------------------------------------------------------------------------

/**
 * A TTL-bound, one-shot grant derived from a responded
 * `authorization.approve` Ask, authorizing ONE tool call matching
 * `(tool, commandPattern)`.
 */
export interface AskGrant {
  /** The Ask this grant derives from. The bridge re-verifies it server-side. */
  askId: string;
  /** Harness tool name the grant applies to (e.g. "Bash", "mcp__minsky__session_exec"). */
  tool: string;
  /**
   * Regular expression the pending command must match. Issuance refuses
   * overbroad patterns (see `isOverbroadPattern`); `--command-exact` callers
   * get an escaped, anchored pattern.
   */
  commandPattern: string;
  /** ISO-8601 timestamp the grant was issued. */
  issuedAt: string;
  /** Grant lifetime in milliseconds from `issuedAt`. */
  ttlMs: number;
  /** Human-readable justification (defaults to the ask's title at issuance). MANDATORY. */
  reason: string;
  /** Free-form audit note identifying the issuing agent/session. */
  issuedBy?: string;
  /** ISO-8601 timestamp the grant was consumed (one-shot marker). Absent = unconsumed. */
  consumedAt?: string;
}

export interface AskGrantMatchContext {
  tool: string;
  command: string;
}

// ---------------------------------------------------------------------------
// Pattern safety
// ---------------------------------------------------------------------------

/**
 * True when `pattern` is too broad to be a safe grant: after stripping regex
 * metacharacters and whitespace, fewer than 12 literal characters remain.
 * A `.*`-shaped grant would auto-allow ANY command on the tool for the TTL —
 * exactly the standing-capability shape this store must never hold.
 */
export function isOverbroadPattern(pattern: string): boolean {
  const literal = pattern.replace(/[.*+?^${}()|[\]\\]/g, "").replace(/\s+/g, "");
  return literal.length < 12;
}

// ---------------------------------------------------------------------------
// Parse + validate
// ---------------------------------------------------------------------------

function validateGrant(item: unknown): AskGrant | null {
  if (!item || typeof item !== "object") return null;
  const rec = item as Record<string, unknown>;

  if (typeof rec.askId !== "string" || rec.askId.trim().length === 0) return null;
  if (typeof rec.tool !== "string" || rec.tool.trim().length === 0) return null;
  if (typeof rec.commandPattern !== "string" || rec.commandPattern.length === 0) return null;
  if (typeof rec.issuedAt !== "string" || Number.isNaN(Date.parse(rec.issuedAt))) return null;
  if (typeof rec.ttlMs !== "number" || !Number.isFinite(rec.ttlMs) || rec.ttlMs <= 0) return null;
  if (typeof rec.reason !== "string" || rec.reason.trim().length === 0) return null;

  const issuedBy = typeof rec.issuedBy === "string" ? rec.issuedBy : undefined;
  const consumedAt =
    typeof rec.consumedAt === "string" && !Number.isNaN(Date.parse(rec.consumedAt))
      ? rec.consumedAt
      : undefined;

  return {
    askId: rec.askId,
    tool: rec.tool,
    commandPattern: rec.commandPattern,
    issuedAt: rec.issuedAt,
    ttlMs: rec.ttlMs,
    reason: rec.reason,
    issuedBy,
    consumedAt,
  };
}

/**
 * Parse the raw store contents into a validated grant array. Malformed
 * individual entries are skipped; `null` only when the top-level JSON is
 * unparseable or not `{ grants: [...] }` (a genuine READ ERROR).
 */
export function parseAskGrantStoreContent(raw: string): AskGrant[] | null {
  let parsed: unknown;
  try {
    parsed = JSON.parse(raw);
  } catch {
    return null;
  }
  if (
    !parsed ||
    typeof parsed !== "object" ||
    !Array.isArray((parsed as { grants?: unknown }).grants)
  ) {
    return null;
  }
  const grants: AskGrant[] = [];
  for (const item of (parsed as { grants: unknown[] }).grants) {
    const validated = validateGrant(item);
    if (validated) grants.push(validated);
  }
  return grants;
}

// ---------------------------------------------------------------------------
// Injectable fs dependency (mirrors guard-grant-store.ts)
// ---------------------------------------------------------------------------

export interface AskGrantStoreFsDeps {
  readFileSync: (path: string) => string;
  writeFileSync: (path: string, content: string) => void;
  mkdirSync: (path: string) => void;
}

const defaultFsDeps: AskGrantStoreFsDeps = {
  readFileSync: (p: string): string => fs.readFileSync(p, "utf8"),
  writeFileSync: (p: string, content: string): void => {
    fs.writeFileSync(p, content, "utf8");
  },
  mkdirSync: (p: string): void => {
    fs.mkdirSync(p, { recursive: true });
  },
};

// ---------------------------------------------------------------------------
// Store lock (PR #2015 R1 — one-shot must hold under concurrent invocations)
// ---------------------------------------------------------------------------
//
// `consumeAskGrant` is a read-modify-write; without mutual exclusion two
// near-simultaneous hook invocations could both match the same grant, both
// mark it consumed, and both emit "allow" — violating the single-use
// guarantee. Mutual exclusion via atomic exclusive-create of a sibling
// `.lock` file (O_EXCL): the creator holds the lock; a stale lock (older
// than LOCK_STALE_MS, e.g. a crashed holder) is reclaimed.

const LOCK_SUFFIX = ".lock";
const LOCK_STALE_MS = 10_000;
const LOCK_RETRIES = 40;
const LOCK_RETRY_DELAY_MS = 25;

export interface AskGrantLockDeps {
  /** Atomically create the lock file; false when it already exists. */
  tryExclusiveCreate: (path: string, content: string) => boolean;
  unlinkSync: (path: string) => void;
  /** Age of the lock file in ms, or null when missing/unreadable. */
  lockAgeMs: (path: string) => number | null;
  sleepMs: (ms: number) => void;
}

const defaultLockDeps: AskGrantLockDeps = {
  tryExclusiveCreate: (p: string, content: string): boolean => {
    try {
      const fd = fs.openSync(p, "wx");
      fs.writeSync(fd, content);
      fs.closeSync(fd);
      return true;
    } catch (err) {
      if ((err as NodeJS.ErrnoException)?.code === "EEXIST") return false;
      throw err;
    }
  },
  unlinkSync: (p: string): void => {
    try {
      fs.unlinkSync(p);
    } catch {
      // Already gone — fine.
    }
  },
  lockAgeMs: (p: string): number | null => {
    try {
      return Date.now() - fs.statSync(p).mtimeMs;
    } catch {
      return null;
    }
  },
  sleepMs: (ms: number): void => {
    Bun.sleepSync(ms);
  },
};

/**
 * Run `fn` holding the store's sibling lock file. Throws when the lock
 * cannot be acquired within the retry budget (~1s) — callers decide whether
 * that is fatal (issuance) or a defer (consumption).
 */
export function withAskGrantStoreLock<T>(
  storePath: string,
  fn: () => T,
  lockDeps: AskGrantLockDeps = defaultLockDeps
): T {
  const lockPath = `${storePath}${LOCK_SUFFIX}`;
  for (let attempt = 0; attempt < LOCK_RETRIES; attempt++) {
    if (lockDeps.tryExclusiveCreate(lockPath, `${process.pid} ${new Date().toISOString()}`)) {
      try {
        return fn();
      } finally {
        lockDeps.unlinkSync(lockPath);
      }
    }
    const age = lockDeps.lockAgeMs(lockPath);
    if (age !== null && age > LOCK_STALE_MS) {
      lockDeps.unlinkSync(lockPath);
      continue;
    }
    lockDeps.sleepMs(LOCK_RETRY_DELAY_MS);
  }
  throw new Error(`could not acquire ask-grant store lock at ${lockPath}`);
}

// ---------------------------------------------------------------------------
// Read path
// ---------------------------------------------------------------------------

export type AskGrantStoreReadResult =
  | { status: "ok"; grants: AskGrant[] }
  | { status: "error"; message: string };

/**
 * Read + parse the grant store. File absent -> confirmed zero-grants state.
 * Unreadable/malformed -> `{ status: "error" }` — the BRIDGE treats this as
 * "no grant" (falls through to the normal permission flow, which is the safe
 * direction for an allow-emitting hook; contrast the D8 read path where
 * fail-open means permitting).
 */
export function readAskGrantStore(
  storePath: string,
  fsDeps: AskGrantStoreFsDeps = defaultFsDeps
): AskGrantStoreReadResult {
  let raw: string;
  try {
    raw = fsDeps.readFileSync(storePath);
  } catch (err) {
    const code = (err as NodeJS.ErrnoException)?.code;
    if (code === "ENOENT") {
      return { status: "ok", grants: [] };
    }
    return { status: "error", message: err instanceof Error ? err.message : String(err) };
  }

  const grants = parseAskGrantStoreContent(raw);
  if (grants === null) {
    return { status: "error", message: `malformed ask grant store JSON at ${storePath}` };
  }
  return { status: "ok", grants };
}

// ---------------------------------------------------------------------------
// Matching
// ---------------------------------------------------------------------------

/**
 * True when `grant` is currently valid for `ctx`: unconsumed, unexpired,
 * same tool, and `commandPattern` matches the pending command. A pattern
 * that fails to compile as a RegExp never matches (conservative).
 */
export function isAskGrantValid(
  grant: AskGrant,
  ctx: AskGrantMatchContext,
  nowMs: number
): boolean {
  if (grant.consumedAt !== undefined) return false;
  const issuedMs = Date.parse(grant.issuedAt);
  if (Number.isNaN(issuedMs)) return false;
  if (nowMs >= issuedMs + grant.ttlMs) return false; // expired
  if (grant.tool !== ctx.tool) return false;

  let re: RegExp;
  try {
    re = new RegExp(grant.commandPattern);
  } catch {
    return false;
  }
  return re.test(ctx.command);
}

/** Return the first grant valid for `ctx` at `nowMs`, or null. */
export function findValidAskGrant(
  grants: AskGrant[],
  ctx: AskGrantMatchContext,
  nowMs: number
): AskGrant | null {
  return grants.find((g) => isAskGrantValid(g, ctx, nowMs)) ?? null;
}

// ---------------------------------------------------------------------------
// Write paths
// ---------------------------------------------------------------------------

function pruneExpired(grants: AskGrant[], nowMs: number): AskGrant[] {
  return grants.filter((g) => {
    const issuedMs = Date.parse(g.issuedAt);
    return !Number.isNaN(issuedMs) && nowMs < issuedMs + g.ttlMs;
  });
}

/**
 * Append `grant` to the store, pruning expired grants (consumed grants are
 * retained until expiry as an audit trace). Creates the state dir/store if
 * absent. A corrupt existing store starts fresh — issuance is an explicit
 * action; the read side's conservatism is what protects the bridge.
 * Holds the store lock for the read-modify-write (throws on lock failure —
 * issuance fails loudly rather than risking a lost concurrent update).
 */
export function appendAskGrant(
  storePath: string,
  grant: AskGrant,
  fsDeps: AskGrantStoreFsDeps = defaultFsDeps,
  nowMs: number = Date.now(),
  lockDeps: AskGrantLockDeps = defaultLockDeps
): void {
  fsDeps.mkdirSync(path.dirname(storePath));

  withAskGrantStoreLock(
    storePath,
    () => {
      const existing = readAskGrantStore(storePath, fsDeps);
      const currentGrants = existing.status === "ok" ? existing.grants : [];
      const unexpired = pruneExpired(currentGrants, nowMs);

      unexpired.push(grant);
      fsDeps.writeFileSync(storePath, `${JSON.stringify({ grants: unexpired }, null, 2)}\n`);
    },
    lockDeps
  );
}

/**
 * Mark `grant` consumed (one-shot). Identity is (askId, tool, commandPattern,
 * issuedAt) — the tuple that uniquely identifies an issuance. Returns true
 * when a matching unconsumed grant was found and marked; false otherwise
 * (caller must then NOT emit an allow — losing the race means the grant was
 * already spent). The read-modify-write holds the store lock; a lock-
 * acquisition failure returns false (defer — never allow without a
 * confirmed exclusive consume).
 */
export function consumeAskGrant(
  storePath: string,
  grant: AskGrant,
  fsDeps: AskGrantStoreFsDeps = defaultFsDeps,
  nowMs: number = Date.now(),
  lockDeps: AskGrantLockDeps = defaultLockDeps
): boolean {
  try {
    return withAskGrantStoreLock(
      storePath,
      () => {
        const existing = readAskGrantStore(storePath, fsDeps);
        if (existing.status !== "ok") return false;

        let marked = false;
        const updated = existing.grants.map((g) => {
          if (
            !marked &&
            g.consumedAt === undefined &&
            g.askId === grant.askId &&
            g.tool === grant.tool &&
            g.commandPattern === grant.commandPattern &&
            g.issuedAt === grant.issuedAt
          ) {
            marked = true;
            return { ...g, consumedAt: new Date(nowMs).toISOString() };
          }
          return g;
        });

        if (!marked) return false;
        fsDeps.mkdirSync(path.dirname(storePath));
        fsDeps.writeFileSync(storePath, `${JSON.stringify({ grants: updated }, null, 2)}\n`);
        return true;
      },
      lockDeps
    );
  } catch {
    return false;
  }
}
